import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';

export default function AdminCommunities() {
  const [communities, setCommunities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState('');

  const fetchCommunities = async () => {
    setLoading(true);
    try {
      const params = statusFilter ? `?status=${statusFilter}` : '';
      const res = await api.get(`/communities/all${params}`);
      setCommunities(res.data.data || []);
    } catch { toast.error('Failed to load communities'); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchCommunities(); }, [statusFilter]);

  const approveCommunity = async (id, name) => {
    try {
      await api.put(`/communities/${id}/approve`);
      toast.success(`${name} approved`);
      fetchCommunities();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  return (
    <div className="page-wrapper">
      <div className="container">
        <div className="page-header">
          <div className="flex-between">
            <div>
              <h2 style={{ fontFamily: 'var(--font-display)', marginBottom: 4 }}>COMMUNITY <span className="gradient-text">MANAGEMENT</span></h2>
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>{communities.length} communities</p>
            </div>
            <Link to="/admin" className="btn btn-outline">← Dashboard</Link>
          </div>
        </div>

        {/* Filter tabs */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
          {[['', 'All'], ['pending', 'Pending'], ['approved', 'Approved'], ['rejected', 'Rejected']].map(([v, l]) => (
            <button key={v} onClick={() => setStatusFilter(v)} className={`btn btn-sm ${statusFilter === v ? 'btn-primary' : 'btn-outline'}`}>{l}</button>
          ))}
        </div>

        {loading ? (
          <div className="loading-screen"><div className="spinner" /></div>
        ) : communities.length === 0 ? (
          <div className="empty-state"><div className="empty-state-icon">🏛️</div><div>No communities found</div></div>
        ) : (
          <div className="grid grid-3">
            {communities.map(c => (
              <div key={c._id} className="card">
                <div style={{ display: 'flex', alignItems: 'flex-start', gap: 14, marginBottom: 14 }}>
                  <div className="avatar avatar-lg" style={{ borderRadius: 10, background: 'linear-gradient(135deg, var(--purple-primary), var(--blue-accent))' }}>
                    {c.name?.charAt(0)}
                  </div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 700, fontSize: '0.95rem', marginBottom: 4 }}>{c.name}</div>
                    <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                      <span className={`badge badge-${c.status}`}>{c.status}</span>
                      <span className={`badge badge-${c.category?.toLowerCase()}`}>{c.category}</span>
                    </div>
                  </div>
                </div>

                <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', lineHeight: 1.6, marginBottom: 14 }}>
                  {c.description?.substring(0, 100)}...
                </p>

                <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginBottom: 14 }}>
                  👤 Admin: <span style={{ color: 'var(--text-secondary)' }}>{c.admin?.name}</span>
                  <br />
                  📅 <span style={{ color: 'var(--text-secondary)' }}>{new Date(c.createdAt).toLocaleDateString()}</span>
                </div>

                {c.status === 'pending' && (
                  <div style={{ display: 'flex', gap: 8 }}>
                    <button onClick={() => approveCommunity(c._id, c.name)} className="btn btn-success btn-sm" style={{ flex: 1, justifyContent: 'center' }}>✓ Approve</button>
                    <button className="btn btn-danger btn-sm" style={{ flex: 1, justifyContent: 'center' }} onClick={async () => {
                      const reason = prompt('Rejection reason:');
                      if (!reason) return;
                      try { await api.put(`/communities/${c._id}/reject`, { reason }); toast.success('Rejected'); fetchCommunities(); }
                      catch { toast.error('Failed'); }
                    }}>✗ Reject</button>
                  </div>
                )}
                {c.status === 'approved' && (
                  <Link to={`/clubs/${c._id}`} className="btn btn-outline btn-sm" style={{ justifyContent: 'center' }}>View Public Page</Link>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
